import { ref, onMounted, watch } from 'vue'
import { profile } from '@/api/profile'
import { showToast } from '@/components/ToastMessage'
import store from '@/store'

export function useProfileData() {
  const resumeData = ref({
    id: null,
    name: '',
    avatar: '',
    gender: '',
    birth_date: '',
    phone: '',
    email: '',
    location: '',
    personal_summary: '',
    created_at: '',
    updated_at: ''
  })

  // 从 store 初始化数据
  const initFromStore = () => {
    const userInfo = store.getters.getUserInfo
    console.log('从 store 获取用户信息:', userInfo)
    console.log('当前 store 状态:', store.state.user)

    if (userInfo) {
      resumeData.value = {
        ...resumeData.value,
        id: userInfo.id,
        name: userInfo.name || '',
        avatar: userInfo.avatar || '',
        gender: userInfo.gender || '',
        birth_date: userInfo.birth_date || '',
        phone: userInfo.phone || '',
        email: userInfo.email || '',
        location: userInfo.location || '',
        personal_summary: userInfo.personal_summary || '',
        created_at: userInfo.created_at || '',
        updated_at: userInfo.updated_at || ''
      }
      console.log('初始化后的数据:', resumeData.value)
    } else {
      console.log('未找到用户信息')
    }
  }

  // 监听 store 中的用户信息变化
  watch(() => store.getters.getUserInfo, (newVal) => {
    console.log('Store 用户信息变化:', newVal)
    if (newVal) {
      initFromStore()
    }
  }, { deep: true })

  // 添加调试日志
  console.log('useProfileData initialized:', resumeData.value)

  // 添加个人简介展开状态控制
  const bioExpanded = ref(false)
  const showBioExpandButton = ref(false)

  // 切换个人简介展开状态
  const toggleBioExpand = () => {
    bioExpanded.value = !bioExpanded.value
  }

  const loading = ref(false)
  const error = ref(null)

  const fetchInitialData = async () => {
    loading.value = true
    error.value = null
    try {
      const response = await profile.getBasicInfo()
      console.log('API 响应数据:', response.data)

      if (response.data?.data) {
        const data = response.data.data
        resumeData.value = {
          id: data.id,
          name: data.name,
          avatar: data.avatar,
          gender: data.gender,
          birth_date: data.birth_date,
          phone: data.phone,
          email: data.email,
          location: data.location,
          personal_summary: data.personal_summary,
          created_at: data.created_at,
          updated_at: data.updated_at
        }
        console.log('更新后的数据:', resumeData.value)
        showBioExpandButton.value = data.personal_summary?.length > 100
      } else {
        throw new Error('获取资料失败：无数据返回')
      }
    } catch (err) {
      console.error('获取用户资料失败:', err)
      error.value = err.message || '获取用户资料失败'
      showToast(error.value, 'error')
    } finally {
      loading.value = false
    }
  }

  const updateResumeData = async (data) => {
    loading.value = true
    error.value = null
    try {
      console.log('开始更新数据...')
      console.log('原始表单数据:', data)

      // 处理提交的数据
      const submitData = {
        name: data.name || '',
        gender: data.gender || '',
        phone: data.phone || '',
        email: data.email || '',
        location: data.location || '',
        birth_date: data.birth_date || null,  // 确保日期为 null 而不是空字符串
        personal_summary: data.personal_summary || ''
      }

      // 移除所有空字符串值
      Object.keys(submitData).forEach(key => {
        if (submitData[key] === '') {
          submitData[key] = null
        }
      })

      console.log('处理后的提交数据:', submitData)
      const response = await profile.updateBasicInfo(submitData)
      console.log('更新响应:', response)

      if (response?.data?.data) {
        const responseData = response.data.data
        resumeData.value = {
          id: responseData.id,
          name: responseData.name,
          avatar: responseData.avatar,
          gender: responseData.gender,
          birth_date: responseData.birth_date,
          phone: responseData.phone,
          email: responseData.email,
          location: responseData.location,
          personal_summary: responseData.personal_summary,
          created_at: responseData.created_at,
          updated_at: responseData.updated_at
        }
        console.log('更新后的数据:', resumeData.value)
        showToast('更新成功', 'success')
        return true
      }

      throw new Error(response?.message || '更新失败，请稍后重试')
    } catch (err) {
      console.error('更新用户资料失败:', err)
      if (err.response?.data) {
        console.log('错误详情:', err.response.data)
      }
      error.value = err.message || '更新用户资料失败'
      showToast(error.value, 'error')
      return false
    } finally {
      loading.value = false
    }
  }

  // 获取处理后的个人简介文本
  const getBioText = () => {
    const text = resumeData.value.personal_summary
    if (!text) return ''
    if (!bioExpanded.value && text.length > 100) {
      return text.slice(0, 100) + '...'
    }
    return text
  }

  // 添加清理方法
  const cleanup = () => {
    resumeData.value = {
      id: null,
      name: '',
      avatar: '',
      gender: '',
      birth_date: '',
      phone: '',
      email: '',
      location: '',
      personal_summary: '',
      created_at: '',
      updated_at: ''
    }
    bioExpanded.value = false
    showBioExpandButton.value = false
    loading.value = false
    error.value = null
  }

  onMounted(async () => {
    console.log('组件挂载')
    // 先从 store 初始化
    initFromStore()
    // 如果 store 中没有数据，从 API 获取
    if (!store.getters.getUserInfo) {
      console.log('Store 中无数据，从 API 获取')
      await store.dispatch('fetchUserInfo')
    }
    // 然后从 API 获取最新数据
    await fetchInitialData()
  })

  // 监听数据变化
  watch(() => resumeData.value, (newVal, oldVal) => {
    console.log('resumeData 变化:', {
      old: oldVal,
      new: newVal
    })
  }, { deep: true })

  return {
    resumeData,
    loading,
    error,
    bioExpanded,
    showBioExpandButton,
    toggleBioExpand,
    getBioText,
    fetchInitialData,
    updateResumeData,
    cleanup
  }
}
